from a2a.server.agent_execution import AgentExecutor, RequestContextfrom a2a.server.events import EventQueuefrom a2a.utils import new_agent_text_messagefrom openai import OpenAIclient = OpenAI(api_key="...")class RecipeAgent:    """Recipe Agent."""    async def invoke(self, prompt):        response = client.responses.create(model="gpt-3.5-turbo",                                           input=prompt)        return response.output_textclass RecipeAgentExecutor(AgentExecutor):    """Test AgentProxy Implementation."""    def __init__(self):        self.agent = RecipeAgent()    async def execute(self, context: RequestContext, event_queue: EventQueue):        result = await self.agent.invoke(prompt=context.get_user_input())        await event_queue.enqueue_event(new_agent_text_message(result))    async def cancel(self, context: RequestContext, event_queue: EventQueue):        raise Exception('cancel not supported')